class Graph:
    def __init__(self, num_vertices):
        self.num_vertices = num_vertices
        self.adj_matrix = [[0] * num_vertices for _ in range(num_vertices)]

    def add_edge(self, u, v):
        if 0 <= u < self.num_vertices and 0 <= v < self.num_vertices:
            self.adj_matrix[u][v] = 1
            self.adj_matrix[v][u] = 1

    def remove_edge(self, u, v):
        if 0 <= u < self.num_vertices and 0 <= v < self.num_vertices:
            self.adj_matrix[u][v] = 0
            self.adj_matrix[v][u] = 0

    def has_edge(self, u, v):
        if 0 <= u < self.num_vertices and 0 <= v < self.num_vertices:
            return self.adj_matrix[u][v] == 1
        return False

    def __str__(self):
        matrix_str = ""
        for row in self.adj_matrix:
            matrix_str += " ".join(map(str, row)) + "\n"
        return matrix_str.strip()

if __name__ == '__main__':
    g = Graph(4)
    g.add_edge(0, 1)
    g.add_edge(0, 2)
    g.add_edge(1, 2)
    g.add_edge(2, 3)

    print("Initial Graph Adjacency Matrix:")
    print(g)

    print("\nDoes edge (0, 1) exist?", g.has_edge(0, 1))
    print("Does edge (0, 3) exist?", g.has_edge(0, 3))

    g.remove_edge(1, 2)
    print("\nGraph after removing edge (1, 2):")
    print(g)
    print("Does edge (1, 2) exist?", g.has_edge(1, 2))
